func hasPermission(playerRole PlayerRole, requiredRole PlayerRole) bool {
	roleHierarchy := map[PlayerRole]int{
		RolePlayer:    0,
		RoleModerator: 1,
		RoleAdmin:     2,
	}

	playerLevel, ok1 := roleHierarchy[playerRole]
	requiredLevel, ok2 := roleHierarchy[requiredRole]

	if !ok1 || !ok2 {
		return false
	}

	return playerLevel >= requiredLevel
}

func handleKick(gs *GameServer, sender *Player, args []string) string {
	if len(args) < 1 {
		return "Usage: /kick <player_name> [reason]"
	}

	targetName := args[0]
	reason := "No reason provided"
	if len(args) > 1 {
		reason = strings.Join(args[1:], " ")
	}

	gs.mu.Lock()
	defer gs.mu.Unlock()

	for _, player := range gs.players {
		if player.Name == targetName {
			if hasPermission(player.Role, sender.Role) && player.ID != sender.ID {
				return fmt.Sprintf("Cannot kick %s: they have equal or higher privileges", targetName)
			}

			kickMsg := ServerMessage{
				Type:    "kicked",
				From:    "SERVER",
				Content: fmt.Sprintf("You have been kicked by %s. Reason: %s", sender.Name, reason),
			}
			sendMessage(player.Conn, kickMsg)
			player.Conn.Close()
			delete(gs.players, player.ID)

			gs.broadcastLocked(ServerMessage{
				Type:    "system",
				From:    "SERVER",
				Content: fmt.Sprintf("%s has been kicked by %s. Reason: %s", targetName, sender.Name, reason),
			})

			return fmt.Sprintf("Player %s has been kicked", targetName)
		}
	}

	return fmt.Sprintf("Player %s not found", targetName)
}

