func handleGiveItems(gs *GameServer, sender *Player, args []string) string {
	if len(args) < 3 {
		return "Usage: /giveitems <player_name> <item_name> <quantity>"
	}

	targetName := args[0]
	itemName := args[1]
	quantity := 0
	_, err := fmt.Sscanf(args[2], "%d", &quantity)
	if err != nil || quantity <= 0 {
		return "Invalid quantity. Must be a positive integer."
	}

	gs.mu.Lock()
	defer gs.mu.Unlock()

	for _, player := range gs.players {
		if player.Name == targetName {
			if player.Items == nil {
				player.Items = make(map[string]int)
			}
			player.Items[itemName] += quantity

			itemMsg := ServerMessage{
				Type:    "item_received",
				From:    "SERVER",
				Content: fmt.Sprintf("You received %d x %s from admin %s", quantity, itemName, sender.Name),
			}
			sendMessage(player.Conn, itemMsg)

			return fmt.Sprintf("Gave %d x %s to %s", quantity, itemName, targetName)
		}
	}

	return fmt.Sprintf("Player %s not found", targetName)
}

