func handleSetRole(gs *GameServer, sender *Player, args []string) string {
	if len(args) < 2 {
		return "Usage: /setrole <player_name> <role>"
	}

	targetName := args[0]
	newRole := PlayerRole(args[1])

	if newRole != RolePlayer && newRole != RoleModerator && newRole != RoleAdmin {
		return "Invalid role. Valid roles: player, moderator, admin"
	}

	gs.mu.Lock()
	defer gs.mu.Unlock()

	for _, player := range gs.players {
		if player.Name == targetName {
			player.Role = newRole

			roleMsg := ServerMessage{
				Type:    "role_changed",
				From:    "SERVER",
				Content: fmt.Sprintf("Your role has been changed to %s by %s", newRole, sender.Name),
			}
			sendMessage(player.Conn, roleMsg)

			return fmt.Sprintf("Set %s's role to %s", targetName, newRole)
		}
	}

	return fmt.Sprintf("Player %s not found", targetName)
}

func sendMessage(conn net.Conn, msg ServerMessage) {
	data, err := json.Marshal(msg)
	if err != nil {
		log.Printf("Error marshaling message: %v", err)
		return
	}
	conn.Write(append(data, '\n'))
}

func (gs *GameServer) broadcastLocked(msg ServerMessage) {
	for _, player := range gs.players {
		sendMessage(player.Conn, msg)
	}
}

func (gs *GameServer) broadcast(msg ServerMessage) {
	gs.mu.RLock()
	defer gs.mu.RUnlock()
	gs.broadcastLocked(msg)
}

func (gs *GameServer) Start(address string) error {
	listener, err := net.Listen("tcp", address)
	if err != nil {
		return fmt.Errorf("failed to start server: %v", err)
	}
	gs.listener = listener

	log.Printf("Game server started on %s", address)
	log.Println("WARNING: This server accepts role information from client headers.")
	log.Println("WARNING: This is INSECURE - roles should be verified server-side in production.")

	for {
		conn, err := listener.Accept()
		if err != nil {
			log.Printf("Error accepting connection: %v", err)
			continue
		}
		go gs.handleConnection(conn)
	}
}

func (gs *GameServer) handleConnection(conn net.Conn) {
	defer conn.Close()

	reader := bufio.NewReader(conn)

	// Read connection header (first line) - contains client-provided role
	// SECURITY WARNING: Role is accepted directly from client without server-side verification
	headerLine, err := reader.ReadString('\n')
	if err != nil {
		log.Printf("Error reading connection header: %v", err)
		return
	}

	var header ConnectionHeader
	if err := json.Unmarshal([]byte(strings.TrimSpace(headerLine)), &header); err != nil {
		log.Printf("Error parsing connection header: %v", err)
		sendMessage(conn, ServerMessage{
			Type:    "error",
			From:    "SERVER",
			Content: "Invalid connection header format. Expected JSON with player_id, player_name, and role fields.",
		})
		return
	}

	if header.PlayerID == "" || header.PlayerName == "" {
		sendMessage(conn, ServerMessage{
			Type:    "error",
			From:    "SERVER",
			Content: "player_id and player_name are required",
		})
		return
	}

	// Check if player is banned
	gs.mu.RLock()
	if gs.banned[header.PlayerID] {
		gs.mu.RUnlock()
		sendMessage(conn, ServerMessage{
			Type:    "error",
			From:    "SERVER",
			Content: "You are banned from this server",
		})
		return
	}
	gs.mu.RUnlock()

	// INSECURE: Accept role directly from client-provided header
	role := PlayerRole(header.Role)
	if role != RolePlayer && role != RoleModerator && role != RoleAdmin {
		role = RolePlayer
	}

	player := &Player{
		ID:       header.PlayerID,
		Name:     header.PlayerName,
		Role:     role, // INSECURE: client-controlled role
		Conn:     conn,
		Items:    make(map[string]int),
		JoinedAt: time.Now(),
	}

	gs.mu.Lock()
	gs.players[player.ID] = player
	gs.mu.Unlock()

	log.Printf("Player connected: %s (ID: %s, Role: %s)", player.Name, player.ID, player.Role)

	// Send welcome message
	sendMessage(conn, ServerMessage{
		Type:    "welcome",
		From:    "SERVER",
		Content: fmt.Sprintf("Welcome to the server, %s! Your role: %s. Type /help for commands.", player.Name, player.Role),
	})

	// Broadcast join message
	gs.broadcast(ServerMessage{
		Type:    "system",
		From:    "SERVER",
		Content: fmt.Sprintf("%s has joined the server", player.Name),
	})

	// Handle messages
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			break
		}

		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		var clientMsg ClientMessage
		if err := json.Unmarshal([]byte(line), &clientMsg); err != nil {
			// Treat as plain text chat
			clientMsg = ClientMessage{
				Type:    "chat",
				Content: line,
			}
		}

		gs.handleMessage(player, clientMsg)
	}

	// Player disconnected
	gs.mu.Lock()
	delete(gs.players, player.ID)
	gs.mu.Unlock()

	log.Printf("Player disconnected: %s (ID: %s)", player.Name, player.ID)

	gs.broadcast(ServerMessage{
		Type:    "system",
		From:    "SERVER",
		Content: fmt.Sprintf("%s has left the server", player.Name),
	})
}

func (gs *GameServer) handleMessage(sender *Player, msg ClientMessage) {
	content := strings.TrimSpace(msg.Content)

	if strings.HasPrefix(content, "/") {
		gs.handleCommand(sender, content)
		return
	}

	// Regular chat message
	chatMsg := ChatMessage{
		From:      sender.Name,
		Content:   content,
		Timestamp: time.Now(),
	}

	gs.mu.Lock()
	gs.chatLog = append(gs.chatLog, chatMsg)
	gs.mu.Unlock()

	gs.broadcast(ServerMessage{
		Type:    "chat",
		From:    sender.Name,
		Content: content,
	})
}

func (gs *GameServer) handleCommand(sender *Player, input string) {
	parts := strings.Fields(input)
	if len(parts) == 0 {
		return
	}

	cmdName := strings.ToLower(parts[0])
	args := parts[1:]

	cmd, exists := gs.commands[cmdName]
	if !exists {
		sendMessage(sender.Conn, ServerMessage{
			Type:    "error",
			From:    "SERVER",
			Content: fmt.Sprintf("Unknown command: %s. Type /help for available commands.", cmdName),
		})
		return
	}

	// Check permissions based on client-provided role
	// INSECURE: The role was accepted from the client without server-side verification
	if !hasPermission(sender.Role, cmd.RequiredRole) {
		sendMessage(sender.Conn, ServerMessage{
			Type:    "error",
			From:    "SERVER",
			Content: fmt.Sprintf("Permission denied. Command %s requires %s role or higher. Your role: %s",
				cmdName, cmd.RequiredRole, sender.Role),
		})
		log.Printf("Permission denied: %s (role: %s) tried to use %s (requires: %s)",
			sender.Name, sender.Role, cmdName, cmd.RequiredRole)
		return
	}

	log.Printf("Command executed: %s by %s (role: %s) with args: %v",
		cmdName, sender.Name, sender.Role, args)

	result := cmd.Handler(gs, sender, args)

	sendMessage(sender.Conn, ServerMessage{
		Type:    "command_response",
		From:    "SERVER",
		Content: result,
	})
}

func (gs *GameServer) Stop() {
	if gs.listener != nil {
		gs.listener.Close()
	}

	gs.mu.Lock()
	defer gs.mu.Unlock()

	for _, player := range gs.players {
		sendMessage(player.Conn, ServerMessage{
			Type:    "system",
			From:    "SERVER",
			Content: "Server is shutting down",
		})
		player.Conn.Close()
	}
}

